import { useEffect, useState } from "react";
import {
  getStatusStats,
  getPriorityStats,
  getProgress,
  getUserStats,
} from "../services/reportService";

import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
} from "chart.js";

import { Pie, Bar } from "react-chartjs-2";

ChartJS.register(
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement
);

function ReportsPage() {
  const [statusStats, setStatusStats] = useState([]);
  const [priorityStats, setPriorityStats] = useState([]);
  const [userStats, setUserStats] = useState([]);
  const [progress, setProgress] = useState(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const status = await getStatusStats();
      const priority = await getPriorityStats();
      const users = await getUserStats();
      const prog = await getProgress();

      setStatusStats(status);
      setPriorityStats(priority);
      setUserStats(users);
      setProgress(prog);
    } catch (error) {
      console.error("Error loading reports:", error.message);
    }
  };

  const getStatusColor = (status) => {
    if (status === "todo") return "#9CA3AF";
    if (status === "inprogress") return "#F59E0B";
    if (status === "done") return "#10B981";
    return "#6B7280";
  };

  const getPriorityColor = (priority) => {
    if (priority === "low") return "#22C55E";
    if (priority === "medium") return "#F59E0B";
    if (priority === "high") return "#EF4444";
    return "#6B7280";
  };

  const statusChart = {
    labels: statusStats.map((s) => s._id),
    datasets: [
      {
        label: "Tasks by Status",
        data: statusStats.map((s) => s.count),
        backgroundColor: statusStats.map((s) => getStatusColor(s._id)),
        borderColor: statusStats.map((s) => getStatusColor(s._id)),
        borderWidth: 1,
      },
    ],
  };

  const priorityChart = {
    labels: priorityStats.map((p) => p._id),
    datasets: [
      {
        label: "Tasks by Priority",
        data: priorityStats.map((p) => p.count),
        backgroundColor: priorityStats.map((p) => getPriorityColor(p._id)),
        borderColor: priorityStats.map((p) => getPriorityColor(p._id)),
        borderWidth: 1,
      },
    ],
  };

  const userChart = {
    labels: userStats.map((u) => u._id || "Unassigned"),
    datasets: [
      {
        label: "Tasks by User",
        data: userStats.map((u) => u.count),
        backgroundColor: [
          "#3B82F6",
          "#8B5CF6",
          "#14B8A6",
          "#F97316",
          "#EC4899",
          "#84CC16",
        ],
        borderWidth: 1,
      },
    ],
  };

  return (
    <div style={{ padding: "30px", background: "#f9fafb", minHeight: "100vh" }}>
      <h1 style={{ marginBottom: "30px" }}>Project Reports</h1>

      {progress && (
        <div
          style={{
            background: "#ffffff",
            padding: "20px",
            borderRadius: "12px",
            marginBottom: "30px",
            boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
          }}
        >
          <h3>Project Progress</h3>
          <p>
            {progress.doneTasks} / {progress.totalTasks} tasks done
          </p>

          <div
            style={{
              width: "100%",
              height: "20px",
              background: "#e5e7eb",
              borderRadius: "10px",
              overflow: "hidden",
              marginTop: "10px",
            }}
          >
            <div
              style={{
                width: `${progress.progress}%`,
                height: "100%",
                background: "#10B981",
              }}
            />
          </div>

          <p style={{ marginTop: "10px", fontWeight: "bold" }}>
            {progress.progress}% completed
          </p>
        </div>
      )}

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))",
          gap: "25px",
        }}
      >
        <div
          style={{
            background: "#ffffff",
            padding: "20px",
            borderRadius: "12px",
            boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
          }}
        >
          <h3>Tasks by Status</h3>
          <Pie data={statusChart} />
        </div>

        <div
          style={{
            background: "#ffffff",
            padding: "20px",
            borderRadius: "12px",
            boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
          }}
        >
          <h3>Tasks by Priority</h3>
          <Bar data={priorityChart} />
        </div>

        <div
          style={{
            background: "#ffffff",
            padding: "20px",
            borderRadius: "12px",
            boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
          }}
        >
          <h3>Tasks by User</h3>
          <Bar data={userChart} />
        </div>
      </div>
    </div>
  );
}

export default ReportsPage;
